class Solution:
  def binaryExponentiation(self, x: int, n: int) -> int:
    if n == 0:
      return 1
    temp = self.binaryExponentiation(x, n // 2)
    if n % 2 == 0:
      return temp * temp
    else:
      return x * temp * temp

s = Solution()
print(s.binaryExponentiation(5, 2))
