#include <iostream>

class Solution {
 public:
  long long binaryExponentiation(long long x, int n) {
    if (n == 0)
      return 1;
    long long temp = binaryExponentiation(x, n / 2);
    if (n % 2 == 0)
      return temp * temp;
    else
      return x * temp * temp;
  }
};

int main() {
  Solution s;
  std::cout << s.binaryExponentiation(5, 2) << std::endl;
  std::cout << s.binaryExponentiation(2, 10) << std::endl;
  return 0;
}
